import React, { useState } from 'react';

const FreeTrial = () => {
  const [form, setForm] = useState({
    country: 'Pakistan (+92)',
    studentName: '',
    guardian: '',
    email: '',
    whatsapp: '',
    otherContact: '',
    category: 'Not Applicable',
    gradeLevel: '',
    comments: '',
    agreed: false,
  });
  const [errors, setErrors] = useState({});
  const [submitted, setSubmitted] = useState(false);
  const [loading, setLoading] = useState(false);

  const countries = ['Pakistan (+92)', 'United States (+1)', 'United Kingdom (+44)', 'Canada (+1)', 'Australia (+61)', 'UAE (+971)', 'Saudi Arabia (+966)', 'India (+91)'];
  const categories = ['Not Applicable', 'Orphan', 'Low Income', 'General'];
  const grades = ['Select Grade Level', 'Grade 1-5 (Primary)', 'Grade 6-8 (Middle)', 'Grade 9-10 (SSC/Matric)', 'Grade 11-12 (HSSC/Inter)', 'O Level', 'A Level', 'University', 'Other'];

  const validate = () => {
    const errs = {};
    if (!form.studentName.trim()) errs.studentName = 'Student name is required';
    if (!form.email) errs.email = 'Email is required';
    else if (!/\S+@\S+\.\S+/.test(form.email)) errs.email = 'Invalid email';
    if (!form.whatsapp.trim()) errs.whatsapp = 'WhatsApp number is required';
    if (!form.gradeLevel || form.gradeLevel === 'Select Grade Level') errs.gradeLevel = 'Please select grade level';
    if (!form.agreed) errs.agreed = 'You must agree to Terms and Conditions';
    return errs;
  };

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setForm({ ...form, [name]: type === 'checkbox' ? checked : value });
    setErrors({ ...errors, [name]: '' });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length) { setErrors(errs); return; }
    setLoading(true);
    setTimeout(() => { setSubmitted(true); setLoading(false); }, 1200);
  };

  if (submitted) {
    return (
      <div className="page-container">
        <div style={{ textAlign: 'center', padding: '80px 20px' }}>
          <div className="success-circle" style={{ margin: '0 auto 24px' }}>
            <svg width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="2.5"><polyline points="20 6 9 17 4 12"/></svg>
          </div>
          <h2 style={{ fontSize: '28px', fontWeight: '700', color: '#111827', marginBottom: '12px' }}>Request Submitted!</h2>
          <p style={{ color: '#6b7280', fontSize: '16px', maxWidth: '480px', margin: '0 auto' }}>Thank you <strong>{form.studentName}</strong>! We'll contact you on your WhatsApp number to schedule your FREE trial class.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="page-container">
      {/* Hero */}
      <div className="freetrial-hero">
        <h1 className="freetrial-title">Free Trial for Online Tutoring</h1>
        <p className="freetrial-subtitle">Start your learning journey with a FREE trial class</p>
      </div>

      {/* Steps */}
      <div className="steps-section">
        <h2 className="steps-heading">Take your FREE Online Trial Class!</h2>
        <div className="steps-grid">
          <div className="step-card">
            <div className="step-icon" style={{ background: '#2563eb' }}>
              <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="2"><path d="M16 4h2a2 2 0 0 1 2 2v14a2 2 0 0 1-2 2H6a2 2 0 0 1-2-2V6a2 2 0 0 1 2-2h2"/><rect x="8" y="2" width="8" height="4" rx="1" ry="1"/></svg>
            </div>
            <h3 className="step-title">Submit Request</h3>
            <p className="step-desc">Complete our elegant form to begin your journey. All information remains strictly confidential.</p>
          </div>
          <div className="step-card">
            <div className="step-icon" style={{ background: '#7c3aed' }}>
              <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="2"><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg>
            </div>
            <h3 className="step-title">Meet Your Tutor</h3>
            <p className="step-desc">Experience a complimentary 30-minute session with your hand-selected expert educator.</p>
          </div>
          <div className="step-card step-card-active">
            <div className="step-icon" style={{ background: '#059669' }}>
              <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="2"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/></svg>
            </div>
            <h3 className="step-title" style={{ color: '#059669' }}>Begin Learning</h3>
            <p className="step-desc">Continue with bespoke educational sessions crafted exclusively for your needs.</p>
          </div>
        </div>
      </div>

      {/* Form */}
      <div className="form-section">
        <div className="form-container">
          <h2 className="form-section-title">Tuition Request Form</h2>
          <p className="form-section-subtitle">Fill in your details to book your FREE trial class</p>

          <form onSubmit={handleSubmit} noValidate>
            <div className="form-group">
              <label className="form-label">
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#2563eb" strokeWidth="2"><circle cx="12" cy="12" r="10"/><line x1="2" y1="12" x2="22" y2="12"/><path d="M12 2a15.3 15.3 0 0 1 4 10 15.3 15.3 0 0 1-4 10 15.3 15.3 0 0 1-4-10 15.3 15.3 0 0 1 4-10z"/></svg>
                Your Country :
              </label>
              <select name="country" value={form.country} onChange={handleChange} className="form-select">
                {countries.map(c => <option key={c}>{c}</option>)}
              </select>
            </div>

            <div className="form-group">
              <label className="form-label">
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#2563eb" strokeWidth="2"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/><circle cx="12" cy="7" r="4"/></svg>
                Student Name :
              </label>
              <input type="text" name="studentName" placeholder="Enter full name" value={form.studentName} onChange={handleChange} className={`form-input-full ${errors.studentName ? 'error' : ''}`} />
              {errors.studentName && <span className="error-msg">{errors.studentName}</span>}
            </div>

            <div className="form-group">
              <label className="form-label">
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#2563eb" strokeWidth="2"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/><circle cx="12" cy="7" r="4"/></svg>
                Parent/Guardian :
              </label>
              <input type="text" name="guardian" placeholder="Parent/guardian name" value={form.guardian} onChange={handleChange} className="form-input-full" />
            </div>

            <div className="form-group">
              <label className="form-label">
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#2563eb" strokeWidth="2"><path d="M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2z"/><polyline points="22,6 12,13 2,6"/></svg>
                Email Address :
              </label>
              <input type="email" name="email" placeholder="Enter your Email" value={form.email} onChange={handleChange} className={`form-input-full ${errors.email ? 'error' : ''}`} />
              {errors.email && <span className="error-msg">{errors.email}</span>}
            </div>

            <div className="form-group">
              <label className="form-label">
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#25d366" strokeWidth="2"><path d="M21 11.5a8.38 8.38 0 0 1-.9 3.8 8.5 8.5 0 0 1-7.6 4.7 8.38 8.38 0 0 1-3.8-.9L3 21l1.9-5.7a8.38 8.38 0 0 1-.9-3.8 8.5 8.5 0 0 1 4.7-7.6 8.38 8.38 0 0 1 3.8-.9h.5a8.48 8.48 0 0 1 8 8v.5z"/></svg>
                WhatsApp Number :
              </label>
              <div className={`phone-input-wrapper ${errors.whatsapp ? 'error' : ''}`}>
                <span className="phone-prefix">+92</span>
                <input type="tel" name="whatsapp" placeholder="Enter Number" value={form.whatsapp} onChange={handleChange} className="phone-input" />
              </div>
              {errors.whatsapp && <span className="error-msg">{errors.whatsapp}</span>}
            </div>

            <div className="form-group">
              <label className="form-label">
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#2563eb" strokeWidth="2"><path d="M21 11.5a8.38 8.38 0 0 1-.9 3.8 8.5 8.5 0 0 1-7.6 4.7 8.38 8.38 0 0 1-3.8-.9L3 21l1.9-5.7a8.38 8.38 0 0 1-.9-3.8 8.5 8.5 0 0 1 4.7-7.6 8.38 8.38 0 0 1 3.8-.9h.5a8.48 8.48 0 0 1 8 8v.5z"/></svg>
                Other Contact (Optional) :
              </label>
              <input type="tel" name="otherContact" placeholder="Optional contact number" value={form.otherContact} onChange={handleChange} className="form-input-full" />
            </div>

            <div className="form-group">
              <label className="form-label">
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#2563eb" strokeWidth="2"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/><circle cx="12" cy="7" r="4"/></svg>
                Category :
              </label>
              <select name="category" value={form.category} onChange={handleChange} className="form-select">
                {categories.map(c => <option key={c}>{c}</option>)}
              </select>
              <p className="form-hint">Certification/Verification required for Orphan and Low Income Categories</p>
            </div>

            <div className="form-group">
              <label className="form-label">
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#2563eb" strokeWidth="2"><path d="M4 19.5A2.5 2.5 0 0 1 6.5 17H20"/><path d="M6.5 2H20v20H6.5A2.5 2.5 0 0 1 4 19.5v-15A2.5 2.5 0 0 1 6.5 2z"/></svg>
                Grade Level :
              </label>
              <select name="gradeLevel" value={form.gradeLevel} onChange={handleChange} className={`form-select ${errors.gradeLevel ? 'error' : ''}`}>
                {grades.map(g => <option key={g}>{g}</option>)}
              </select>
              {errors.gradeLevel && <span className="error-msg">{errors.gradeLevel}</span>}
            </div>

            <div className="form-group">
              <label className="form-label">
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#2563eb" strokeWidth="2"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg>
                Additional Comments :
              </label>
              <textarea name="comments" placeholder="Special requirements, preferred timings, etc." value={form.comments} onChange={handleChange} className="form-textarea" rows={5} />
            </div>

            <div className="form-group">
              <label className="checkbox-label">
                <input type="checkbox" name="agreed" checked={form.agreed} onChange={handleChange} />
                <span>I agree to the Terms and Conditions</span>
              </label>
              <p className="form-hint">If not checked, the submit button will not be functional</p>
              {errors.agreed && <span className="error-msg">{errors.agreed}</span>}
            </div>

            <button type="submit" className={`btn-submit-trial ${!form.agreed ? 'disabled' : ''}`} disabled={!form.agreed || loading}>
              {loading ? <span className="btn-loading"><span className="spinner-sm"></span> Submitting...</span> : 'Request FREE Trial Class'}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default FreeTrial;
